SELECT kommunenummer FROM kommuner_627ee106072240e99d2b21ec4717bf01.kommune WHERE LOWER(kommunenavn) = 'stavanger';

-- STEP BOUNDARY --

-- STEP 2: query [matrikkeleneiendomskartteig]
SELECT teigid, matrikkelnummertekst, kommunenummer, ST_AsGeoJSON(ST_Transform(omrade,4326)) AS geom_geojson FROM matrikkeleneiendomskartteig_36313fab8faa42d99cb779d86d1ca26d.teig WHERE kommunenummer = '1103';

-- STEP BOUNDARY --

-- STEP 3: query [arealressurskart_ar50]
SELECT DISTINCT arjordbr, arkartstd FROM public."0000_25833_ar50_gdb__ar50" LIMIT 100;

